const now = new Date();
const days = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const currentDay = days[now.getUTCDay()];
const h = String(now.getUTCHours()).padStart(2, '0');
const m = String(now.getUTCMinutes()).padStart(2, '0');
const currentTime = `${h}:${m}:00`;

// Brief generation runs 2 hours before delivery
// We match on weekly_brief_day = today AND calculate if now is ~2hrs before weekly_brief_time
console.log('Weekly brief check:', currentDay, currentTime);

return [{ json: { currentDay, currentTime } }];

const items = $input.first().json;
const prefs = Array.isArray(items) ? items : [items];

if (!prefs || prefs.length === 0 || !prefs[0].id) return [];

// Filter Full Programme + check if ~2hrs before their brief time
const currentTime = $('Check Day and Time').first().json.currentTime;

const matching = prefs.filter(p => {
  if (p.child_profiles?.mode !== 'full_programme') return false;
  // Check if current time is approximately 2hrs before their brief time
  const briefTime = p.weekly_brief_time || '19:30:00';
  const briefH = parseInt(briefTime.split(':')[0]);
  const briefM = parseInt(briefTime.split(':')[1]);
  const currentH = parseInt(currentTime.split(':')[0]);
  const currentM = parseInt(currentTime.split(':')[1]);
  const briefMinutes = briefH * 60 + briefM;
  const currentMinutes = currentH * 60 + currentM;
  const targetGenMinutes = briefMinutes - 120; // 2hrs before
  return Math.abs(currentMinutes - targetGenMinutes) <= 1;
});

console.log(`Found ${matching.length} briefs to generate`);
return matching.map(p => ({ json: p }));

const pref = $input.item.json;
const childId = pref.child_id;
const userId = pref.user_id;
const profile = pref.child_profiles;
const supabaseUrl = 'https://jmdyhxebcosyjyafzsss.supabase.co';

// Calculate week range (Monday to Sunday)
const now = new Date();
const dayOfWeek = now.getUTCDay();
const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const weekStart = new Date(now);
weekStart.setUTCDate(now.getUTCDate() + mondayOffset);
weekStart.setUTCHours(0, 0, 0, 0);
const weekEnd = new Date(weekStart);
weekEnd.setUTCDate(weekStart.getUTCDate() + 6);
weekEnd.setUTCHours(23, 59, 59, 999);

return [{
  json: {
    childId,
    userId,
    profile,
    subscription: pref.push_subscription,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    weekStartISO: weekStart.toISOString(),
    weekEndISO: weekEnd.toISOString()
  }
}];

const sessionsRaw = $input.first().json;
const sessions = Array.isArray(sessionsRaw) ? sessionsRaw : [];

if (sessions.length < 3) {
  console.log(`Only ${sessions.length} sessions this week (need 3+), skipping brief`);
  return [];
}

console.log(`${sessions.length} sessions this week — generating brief`);
return [{ json: { sessions, sessionCount: sessions.length } }];

const weekData = $('Calculate Week Range').first().json;
const profile = weekData.profile;
const sessions = $('Check Minimum Sessions').first().json.sessions;
const sessionCount = $('Check Minimum Sessions').first().json.sessionCount;
const reactionsRaw = $('Fetch Week Reactions').first().json;
const reactions = Array.isArray(reactionsRaw) ? reactionsRaw : [];
const prevBriefRaw = $('Fetch Previous Brief').first().json;
const prevBriefs = Array.isArray(prevBriefRaw) ? prevBriefRaw : [];
const prevBrief = prevBriefs.length > 0 ? prevBriefs[0] : null;
const ctxRaw = $('Fetch Dynamic Context').first().json;
const ctx = Array.isArray(ctxRaw) ? ctxRaw[0] || {} : ctxRaw || {};

const systemPrompt = `You are a warm, perceptive child development observer helping a parent understand what has been happening in their child's emotional world this week through their bedtime stories.

BRIEF STRUCTURE — three sections, plain language, warm tone:

1. WHAT WE NOTICED THIS WEEK (2-3 sentences)
   Summary of the dominant emotional themes across the week.
   Reference specific story moments where powerful. Not a list of nights.

2. PATTERNS (1-2 sentences, only if a genuine pattern exists)
   Something that appeared across multiple nights that is worth naming.
   If no clear pattern exists, return null for this field.
   Do not manufacture patterns from thin data.

3. WHAT TO NOTICE THIS WEEK (2-3 sentences)
   Forward-looking. Specific. Actionable.
   Based on what emerged this week, what should the parent pay attention to?

BRIEF RULES:
- Never clinical. Never diagnostic. Observe and reflect only.
- Never mention the app, the study, or therapeutic frameworks.
- Reference specific story content and characters where it adds meaning.
- If parent reactions show 'didnt_see', weight that theme lower.
- If parent reactions show consistent 'noticed', validate and build on those themes.
- Reference previous week's brief only to note progress, not to repeat.
- Maximum 200 words total across all three sections.
- Plain language a tired parent can read in 90 seconds.

OUTPUT FORMAT — return valid JSON only:
{
  "summary": "...",
  "patterns": "..." or null,
  "week_ahead": "..."
}`;

const sessionsText = sessions.map((s, i) =>
  `Night ${i + 1} (${new Date(s.created_at).toLocaleDateString()}): mode=${s.mode || 'co-creation'}, prompt="${s.story_prompt || 'none'}", themes=${(s.themes || []).join(',') || 'none'}, villain=${s.villain_appeared ?? 'unknown'}`
).join('\n');

const reactionsText = reactions.length > 0
  ? reactions.map(r => {
      const obs = r.observations || [];
      const reacts = r.reactions || [];
      return obs.map((o, i) =>
        `- [${o.type}] "${o.text}" → reaction: ${reacts[i]?.reaction || 'no reaction'}`
      ).join('\n');
    }).join('\n')
  : 'No morning reaction data yet (Week 1)';

const userPrompt = `CHILD PROFILE:
Name: ${profile.name}, Age: ${profile.age}
Personality: ${profile.personality_description || 'Not provided'}
Neuro flags: ${(profile.neuro_flags || []).join(', ') || 'None'}
Fear flags: ${(ctx.fear_flags || []).join(', ') || 'None'}
Current stressors: ${ctx.current_stressors || 'None noted'}

THIS WEEK'S SESSIONS (${sessionCount} nights):
${sessionsText}

THIS WEEK'S MORNING REACTIONS:
${reactionsText}

PREVIOUS WEEK'S BRIEF SUMMARY: ${prevBrief?.brief_content?.summary || 'First week'}

Generate the weekly brief now.`;

// Check stressor freshness
const stressorsUpdated = ctx.stressors_updated_at ? new Date(ctx.stressors_updated_at) : null;
const stressorsStale = stressorsUpdated ? (Date.now() - stressorsUpdated.getTime()) > (14 * 24 * 60 * 60 * 1000) : false;

return [{
  json: {
    claudePayload: {
      model: 'claude-sonnet-4-6-20250514',
      max_tokens: 1024,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    },
    childId: weekData.childId,
    userId: weekData.userId,
    childName: profile.name,
    subscription: weekData.subscription,
    weekStartDate: weekData.weekStartDate,
    weekEndDate: weekData.weekEndDate,
    sessionCount,
    stressorsStale
  }
}];

const response = $input.first().json;
let content = response.content?.[0]?.text || '';
const cleaned = content.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse brief: ${e.message}. Content: ${cleaned.substring(0, 300)}`);
}

if (!parsed.summary || !parsed.week_ahead) {
  throw new Error('Brief missing required sections');
}

const data = $('Build Claude Prompt').first().json;

// Append stressor refresh note if stale
let briefContent = {
  summary: parsed.summary,
  patterns: parsed.patterns || null,
  week_ahead: parsed.week_ahead,
  generated_at: new Date().toISOString()
};

if (data.stressorsStale) {
  briefContent.stressor_refresh_note = "It's been a couple of weeks since you updated what's going on in their life. Worth a quick check in Settings if anything has changed.";
}

console.log('Brief generated for:', data.childName);

return [{ json: { briefContent } }];

const data = $('Build Claude Prompt').first().json;

return [{
  json: {
    subscription: data.subscription,
    payload: {
      title: 'DreamStation',
      body: `Your weekly reflection for ${data.childName} is ready.`,
      tag: 'weekly-brief',
      url: '/?tab=account&section=briefs'
    }
  }
}];
